item.content:encoded:
.searchandfilter input,
.searchandfilter select,
.searchandfilter button {
  border-radius: 10px;
	font-family:montserrat;
}

.zoom-img {
  overflow: hidden;
  transition: transform 0.4s ease;
}

.zoom-img:hover {
  transform: scale(1.025);
	 box-shadow: 0px 5px 10px rgba(42, 42, 42, 1);
}
